/**
 * Async job execution pipeline for the Infrared SDK.
 *
 * Ported from Python SDK `analyses/jobs.py` (~585 lines).
 * Uses raw `fetch` instead of `HttpClient` because the job endpoints
 * require access to response headers (Link header) and non-JSON binary
 * downloads with separate auth handling (S3 presigned URLs).
 *
 * Design note: Async job submission uses plain JSON (Content-Type: application/json),
 * matching the Python SDK's `JobsServiceClient.submit()` which sends `json=body`.
 * Gzip compression was only used by the now-removed sync execution path.
 */

import { gunzipSync, unzipSync } from 'fflate'

import { postZipWithBigPayload } from '../_internal/big-payloads'
import { zipPayloadJson } from '../_internal/big-payloads/zip'
import type { AuthResolver } from '../auth'
import {
  InfraredError,
  JobFailedError,
  JobNotCompletedError,
  JobPollError,
  JobSubmitError,
  JobTimeoutError,
  ResultsDownloadError,
} from '../errors'
import type { Logger } from '../logger'
import {
  type DownloadResult,
  type IJobsService,
  type Job,
  JobStatus,
  jobFromResponse,
  type OnPollCallback,
} from './types'

// ---------------------------------------------------------------------------
// Backoff constants (matching Python SDK)
// ---------------------------------------------------------------------------

const BACKOFF_BASE = 2
const BACKOFF_CAP = 10
const BACKOFF_FLOOR_S = 0.5
const DEFAULT_TIMEOUT_S = 300

// ---------------------------------------------------------------------------
// JobsService
// ---------------------------------------------------------------------------

/**
 * Default timeout for control-plane HTTP requests (3 minutes). Mirrors
 * Python SDK's `(10, 300)` connect/read budget for `/async/{type}` /
 * `/jobs/{id}` endpoints.
 */
const DEFAULT_REQUEST_TIMEOUT_MS = 180000

/**
 * Default timeout for S3 result downloads (10 minutes). Cold-Lambda S3
 * downloads of full-year weather payloads can stream tens of seconds;
 * Python uses `(10, 600)` = 600s read budget. Sharing the 3-minute
 * control budget caused download timeouts on cold path.
 */
const DEFAULT_DOWNLOAD_TIMEOUT_MS = 600000

export interface JobsServiceConfig {
  /** Auth header resolver — supports apiKey + JWT (token / getToken). */
  getAuthHeaders: AuthResolver
  baseUrl: string
  logger: Logger
  /** Maximum backoff delay in seconds. Default: 10 */
  backoffCap?: number
  /**
   * Control-plane request timeout in ms (submit / poll / status).
   * Default: 180_000 (3 minutes), matching Python SDK's API_TIMEOUT_S.
   */
  timeout?: number
  /**
   * S3 download timeout in ms — used by `downloadResults` for the
   * presigned-URL fetch. Default: 600_000 (10 minutes), matching
   * Python SDK's `S3_TIMEOUT_S`. Larger than `timeout` because
   * cold-Lambda S3 fetches can stream slowly.
   */
  downloadTimeout?: number
  /** Bare gateway URL for big-payload presign. Threaded from InfraredClient. */
  gatewayBaseUrl?: string
  /** Lazy big-payload kill switch — re-resolved per call. */
  getBigPayloadEnabled?: () => boolean
  /** Lazy big-payload threshold (bytes) — re-resolved per call. */
  getBigPayloadThresholdBytes?: () => number
}

/**
 * Client for async job submission, polling, and result download.
 *
 * Uses raw `fetch` with separate authenticated and unauthenticated
 * request paths (API vs. S3 presigned URLs). All requests include
 * timeout via AbortController.
 */
export class JobsService implements IJobsService {
  private readonly getAuthHeaders: AuthResolver
  private readonly baseUrl: string
  private readonly logger: Logger
  private readonly backoffCap: number
  private readonly timeout: number
  private readonly downloadTimeout: number
  private readonly gatewayBaseUrl?: string
  private readonly getBigPayloadEnabled: () => boolean
  private readonly getBigPayloadThresholdBytes: () => number

  constructor(config: JobsServiceConfig) {
    this.getAuthHeaders = config.getAuthHeaders
    this.baseUrl = config.baseUrl
    this.logger = config.logger
    this.backoffCap = config.backoffCap ?? BACKOFF_CAP
    this.timeout = config.timeout ?? DEFAULT_REQUEST_TIMEOUT_MS
    this.downloadTimeout = config.downloadTimeout ?? DEFAULT_DOWNLOAD_TIMEOUT_MS
    this.gatewayBaseUrl = config.gatewayBaseUrl
    this.getBigPayloadEnabled = config.getBigPayloadEnabled ?? (() => true)
    this.getBigPayloadThresholdBytes =
      config.getBigPayloadThresholdBytes ?? (() => 5 * 1024 * 1024)
  }

  // -- public methods -------------------------------------------------------

  /**
   * Submit an analysis for async execution.
   *
   * POST `{baseUrl}/async/{analysisType}` with a zipped JSON payload
   * (`Content-Type: application/zip`). Mirrors Python SDK 0.4.4
   * `JobsServiceClient.submit`, which dispatches via
   * `post_zip_with_big_payload`. Above the configured threshold the
   * zip is uploaded to S3 via the presign flow and a `$ref` envelope
   * is POSTed to the original URL; below threshold the zip is sent
   * inline (still `application/zip`).
   *
   * Webhook fields are injected at the transport layer (not part of the
   * analysis payload schema).
   */
  async submit(
    analysisType: string,
    payload: Record<string, unknown>,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<Job> {
    const url = `${this.baseUrl}/async/${encodeURIComponent(analysisType)}`
    const body = { ...payload }

    // Inject webhook fields at transport layer
    if (opts?.webhookUrl !== undefined) {
      body['webhook-url'] = opts.webhookUrl
    }
    if (opts?.webhookEvents !== undefined) {
      body['webhook-events'] = opts.webhookEvents
    }

    this.logger.debug({ event: 'job_submit', url, analysisType })

    const rawBytes = new TextEncoder().encode(JSON.stringify(body))
    const zipBytes = zipPayloadJson(rawBytes)
    // Resolve auth + big-payload knobs at call time — JWT refresh / env
    // var flips propagate without rebuilding the service.
    const authHeaders = await this.getAuthHeaders()

    // postZipWithBigPayload returns whatever parseResponse returns. Below
    // threshold the zip is POSTed inline; above threshold the envelope path
    // (presign → S3 PUT → `$ref` POST) takes over with REF_EXPIRED retry.
    return await postZipWithBigPayload<Job>({
      url,
      zipBytes,
      authHeaders,
      gatewayBaseUrl: this.gatewayBaseUrl ?? '',
      thresholdBytes: this.getBigPayloadThresholdBytes(),
      enabled: this.getBigPayloadEnabled() && !!this.gatewayBaseUrl,
      inlineTimeoutMs: this.timeout,
      envelopeTimeoutMs: this.timeout,
      logger: this.logger,
      parseResponse: (status, ok, bodyText, bodyJson) => {
        if (!ok) {
          throw new JobSubmitError(
            `Failed to submit ${analysisType} job: ${status} - ${bodyText}`,
            { statusCode: status, responseBody: bodyText },
          )
        }
        return jobFromResponse(bodyJson as Record<string, unknown>)
      },
    })
  }

  /**
   * Poll job status.
   *
   * GET `{baseUrl}/async/jobs/{jobId}`.
   */
  async getStatus(jobId: string): Promise<Job> {
    const url = `${this.baseUrl}/async/jobs/${encodeURIComponent(jobId)}`
    this.logger.info({ event: 'job_poll', url })

    const response = await this.authenticatedFetch(url, { method: 'GET' })

    if (!response.ok) {
      const text = await response.text()
      const retryAfterHeader = response.headers.get('Retry-After')
      const retryAfter =
        retryAfterHeader !== null && !Number.isNaN(Number(retryAfterHeader))
          ? Number(retryAfterHeader)
          : null
      throw new JobPollError(`Failed to poll job ${jobId}: ${response.status}`, {
        jobId,
        statusCode: response.status,
        responseBody: text,
        retryAfter,
      })
    }

    const data = await response.json()
    return jobFromResponse(data as Record<string, unknown>)
  }

  /**
   * Poll until the job reaches a terminal state or timeout.
   *
   * Uses exponential backoff with full jitter:
   *   delay = max(floor, random(0, min(cap, base * 2^attempt)))
   *
   * @param jobId - The job to poll
   * @param opts.timeout - Maximum seconds to wait (default 300). Must be > 0.
   * @param opts.onPoll - Optional callback fired on every iteration (including terminal).
   *   Return `false` to stop polling early.
   *
   * @throws JobTimeoutError if timeout elapses before terminal state
   * @throws JobFailedError if job reaches Failed status
   */
  async waitForCompletion(
    jobId: string,
    opts?: { timeout?: number; onPoll?: OnPollCallback },
  ): Promise<Job> {
    const timeout = opts?.timeout
    if (timeout !== undefined && timeout <= 0) {
      throw new Error(`timeout must be > 0, got ${timeout}`)
    }
    const effectiveTimeout = timeout ?? DEFAULT_TIMEOUT_S

    const start = performance.now() / 1000
    let attempt = 0

    while (true) {
      const job = await this.getStatus(jobId)
      const elapsed = performance.now() / 1000 - start
      const isTerminal = job.status === JobStatus.Succeeded || job.status === JobStatus.Failed
      // Compute delay only for non-terminal states; pass 0 for terminal
      const nextDelay = isTerminal
        ? 0
        : Math.max(
            BACKOFF_FLOOR_S,
            Math.random() * Math.min(this.backoffCap, BACKOFF_BASE * 2 ** attempt),
          )

      // Fire callback on ALL states including terminal
      if (opts?.onPoll) {
        try {
          const result = await opts.onPoll(job, attempt, elapsed, nextDelay)
          if (result === false) {
            return job
          }
        } catch (callbackError) {
          this.logger.warn({
            event: 'on_poll_error',
            attempt,
            error: String(callbackError),
          })
        }
      }

      // Check terminal states
      if (job.status === JobStatus.Succeeded) {
        return job
      }

      if (job.status === JobStatus.Failed) {
        throw new JobFailedError(`Job ${jobId} failed: ${job.error}`, {
          jobId,
          errorMessage: job.error ?? '',
        })
      }

      // Check timeout before sleeping
      if (elapsed + nextDelay >= effectiveTimeout) {
        throw new JobTimeoutError(`Job ${jobId} timed out after ${elapsed.toFixed(1)}s`, {
          jobId,
        })
      }

      await sleep(nextDelay * 1000)
      attempt++
    }
  }

  /**
   * Download results for a completed job.
   *
   * 1. Verify job has succeeded (skip if `opts.job` is provided)
   * 2. Fetch presigned S3 URL from Link header
   * 3. Download from S3 without auth headers
   * 4. On 403, refresh presigned URL once and retry
   */
  async downloadResults(jobId: string, opts?: { job?: Job }): Promise<DownloadResult> {
    const job = opts?.job ?? (await this.getStatus(jobId))

    if (job.status !== JobStatus.Succeeded) {
      throw new JobNotCompletedError(`Job ${jobId} is not completed (status: ${job.status})`, {
        jobId,
      })
    }

    let presignedUrl = await this.fetchPresignedUrl(jobId)

    // Download from S3 -- no auth headers
    let result = await this.downloadFromS3(presignedUrl)

    if (result === null) {
      // 403 -> refresh presigned URL once and retry
      this.logger.debug({ event: 'presigned_url_refresh', jobId })
      presignedUrl = await this.fetchPresignedUrl(jobId)
      result = await this.downloadFromS3(presignedUrl)

      if (result === null) {
        throw new ResultsDownloadError(
          `Presigned URL still invalid after refresh for job ${jobId}`,
          { statusCode: 403, responseBody: 'Forbidden' },
        )
      }
    }

    return {
      content: result.content,
      presignedUrl,
      jobId,
      contentType: result.contentType,
    }
  }

  /**
   * Decompress ZIP or GZIP content and return parsed JSON dict.
   *
   * Tries ZIP first, then GZIP. If the decompressed JSON is a list,
   * it is normalised to `{ output: <list> }` so callers always receive a dict.
   *
   * Uses fflate for isomorphic decompression (no node:* imports).
   * Uses TextDecoder (not String.fromCharCode) to avoid stack overflow on large grids.
   */
  decompress(content: Uint8Array): Record<string, unknown> {
    let jsonString: string

    // Try ZIP first
    try {
      const unzipped = unzipSync(content)
      const fileNames = Object.keys(unzipped)
      if (fileNames.length === 0) {
        throw new Error('Empty ZIP archive')
      }
      jsonString = new TextDecoder().decode(unzipped[fileNames[0]])
    } catch {
      // Fallback to GZIP
      try {
        const decompressed = gunzipSync(content)
        jsonString = new TextDecoder().decode(decompressed)
      } catch {
        throw new Error('Could not decompress content. Unknown format (not ZIP or GZIP).')
      }
    }

    const parsed: unknown = JSON.parse(jsonString)

    // Normalise bare arrays to { output: array }
    if (Array.isArray(parsed)) {
      return { output: parsed }
    }

    return parsed as Record<string, unknown>
  }

  // -- private helpers ------------------------------------------------------

  /**
   * Make an authenticated fetch request (includes X-Api-Key header + timeout).
   *
   * On timeout, throws InfraredError so callers always receive a typed SDK error.
   */
  private async authenticatedFetch(url: string, init: RequestInit): Promise<Response> {
    const headers = new Headers(init.headers)
    // Resolve auth headers per request — JWT refresh stays live, env-var
    // flips for instrumentation propagate.
    const auth = await this.getAuthHeaders()
    for (const [k, v] of Object.entries(auth)) headers.set(k, v)

    const controller = new AbortController()
    const timeoutId = setTimeout(() => controller.abort(), this.timeout)
    try {
      const response = await fetch(url, { ...init, headers, signal: controller.signal })
      return response
    } catch (error) {
      if (error instanceof Error && error.name === 'AbortError') {
        throw new InfraredError(`Request timed out after ${this.timeout}ms: ${url}`, {
          statusCode: 0,
          responseBody: 'Request timed out',
        })
      }
      throw error
    } finally {
      clearTimeout(timeoutId)
    }
  }

  /**
   * GET /async/jobs/{jobId}/results and extract presigned URL from Link header.
   *
   * Link header format: `<presigned-url>; rel="results"` or just `<presigned-url>`
   */
  private async fetchPresignedUrl(jobId: string): Promise<string> {
    const url = `${this.baseUrl}/async/jobs/${encodeURIComponent(jobId)}/results`
    this.logger.debug({ event: 'fetch_presigned_url', url })

    const response = await this.authenticatedFetch(url, { method: 'GET' })

    if (!response.ok) {
      const text = await response.text()
      throw new ResultsDownloadError(
        `Failed to fetch results URL for job ${jobId}: ${response.status}`,
        { statusCode: response.status, responseBody: text },
      )
    }

    const linkHeader = response.headers.get('Link') ?? ''
    // Extract URL from angle brackets: <https://...>
    const match = linkHeader.match(/<([^>]+)>/)
    const presignedUrl = match ? match[1] : linkHeader.trim()

    if (!presignedUrl) {
      throw new ResultsDownloadError(`No Link header in results response for job ${jobId}`, {
        statusCode: response.status,
        responseBody: await response.text().catch(() => ''),
      })
    }

    return presignedUrl
  }

  /**
   * Download from S3 presigned URL without auth headers.
   *
   * Returns `{ content, contentType }` on success, or `null` on 403
   * (caller should retry with refreshed URL).
   */
  private async downloadFromS3(
    presignedUrl: string,
  ): Promise<{ content: Uint8Array; contentType: string } | null> {
    try {
      // Plain fetch -- no X-Api-Key (S3 rejects it with 403), with the
      // dedicated S3-download timeout (default 10 min vs control plane's
      // 3 min). Cold-Lambda S3 fetches of full-year weather can stream
      // tens of seconds; sharing the control budget caused timeouts.
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), this.downloadTimeout)
      let response: Response
      try {
        response = await fetch(presignedUrl, { signal: controller.signal })
      } catch (error) {
        if (error instanceof Error && error.name === 'AbortError') {
          throw new ResultsDownloadError(`S3 download timed out after ${this.downloadTimeout}ms`, {
            statusCode: 0,
            responseBody: 'Request timed out',
          })
        }
        throw error
      } finally {
        clearTimeout(timeoutId)
      }

      if (response.status === 403) {
        return null
      }

      if (!response.ok) {
        const text = await response.text()
        throw new ResultsDownloadError(`Failed to download from S3: ${response.status}`, {
          statusCode: response.status,
          responseBody: text,
        })
      }

      const buffer = await response.arrayBuffer()
      return {
        content: new Uint8Array(buffer),
        contentType: response.headers.get('Content-Type') ?? '',
      }
    } catch (error) {
      if (error instanceof ResultsDownloadError) {
        throw error
      }
      throw new ResultsDownloadError(`Failed to download from S3: ${error}`, {
        statusCode: 0,
        responseBody: String(error),
      })
    }
  }
}

/** Sleep for the given number of milliseconds. */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}
